  JOIN tmp_supply_map m ON m.poster_supply_id = x.poster_supply_id
  JOIN household_chemicals.products p ON p.poster_ingredient_id = x.poster_ingredient_id
  ON CONFLICT DO NOTHING;

  RAISE NOTICE 'Receipt items inserted';

  -- Обновление остатков
  FOR v_item IN
    SELECT ri.receipt_id, ri.product_id, ri.quantity, r.warehouse_id
    FROM household_chemicals.receipt_items ri
    JOIN household_chemicals.receipts r ON r.id = ri.receipt_id
    WHERE r.poster_supply_id IS NOT NULL
      AND r.id NOT IN (SELECT DISTINCT reference_id FROM household_chemicals.stock_movements WHERE reference_type = 'receipt')
  LOOP
    PERFORM household_chemicals.update_stock_balance(
      v_item.product_id, v_item.warehouse_id, v_item.quantity,
      'receipt', 'receipt', v_item.receipt_id,
      'Імпорт з Poster: історія постачання', NULL
    );
    v_item_count := v_item_count + 1;
  END LOOP;

  DROP TABLE IF EXISTS tmp_supply_map;

  RAISE NOTICE 'Done: % receipts, % items processed', 719, v_item_count;
END;
